import numpy as np

def compare_vectors_with_threshold(vec1, vec2, threshold=0.001):
    """
    Compare two vectors using Euclidean distance.
    Returns True if distance is below threshold.
    """
    v1 = np.array(vec1)
    v2 = np.array(vec2)

    if v1.shape != v2.shape:
        return False

    distance = np.linalg.norm(v1 - v2)

    print(f"Distance: {distance}")

    return distance < threshold


